// Agent 5: format output as standard envelope
// Mode: Run Once for All Items
// Reads from Call LLM's normalized response.
// Propagates structured error from Call LLM on failure.
// Output shape: flat issues[] with a per-issue severity field (aligned with Agents 3/4).
// Counts (critical/major/minor/total) are derived in-node from issues[].severity.

const callLLM = $('Call LLM').first().json;

// Empty result shape returned on any failure (must match the success shape).
const emptyResult = {
  summary: '',
  issues: [],
  preserve: [],
  total_issues: 0,
  critical_count: 0,
  major_count: 0,
  minor_count: 0
};

// Call LLM failed â€” propagate error
if (callLLM.success === false) {
  console.log(`[Agent 5] LLM call failed: ${callLLM.error?.category || 'unknown'} â€” ${callLLM.error?.message || 'no message'}`);
  return {
    json: {
      success: false,
      ...emptyResult,
      tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
      cached_input_tokens: callLLM.cached_input_tokens || 0,
      cache_write_tokens: callLLM.cache_write_tokens || 0,
      model_used: callLLM.model_used || 'unknown',
      provider_used: callLLM.provider_used || 'unknown',
      errors: [...(callLLM.errors || [])],
      error: callLLM.error || {
        category: 'unknown',
        type: 'unknown',
        message: 'Call LLM returned success: false with no error object',
        provider: callLLM.provider_used || 'unknown',
        model: callLLM.model_used || 'unknown'
      }
    }
  };
}

// Normal path: parse JSON from content
const response = $input.item.json;
const text = response.text || response.content || response.response || response.output_text || response.completion || '';

const rawText = String(text);
let parsed = null;
const parseErrors = [];

const tryParse = (str) => {
  try { return JSON.parse(str); } catch (e) { return null; }
};

// Strategy 1: strip markdown fences, parse direct
let cleaned = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
parsed = tryParse(cleaned);

// Strategy 2: extract from first { to last } (handles trailing commentary)
if (!parsed) {
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace > firstBrace) {
    parsed = tryParse(cleaned.substring(firstBrace, lastBrace + 1));
  }
}

if (!text) {
  parseErrors.push(`No text returned from Call LLM. Keys: ${Object.keys(response).join(', ')}`);
  console.log(`[Agent 5] ${parseErrors[parseErrors.length - 1]}`);
} else if (!parsed) {
  parseErrors.push(`Could not parse JSON. Start: ${rawText.substring(0, 300)}`);
  console.log(`[Agent 5] JSON parse failed. Raw content (first 500 chars):\n${rawText.slice(0, 500)}`);
}

const success = parsed !== null;
const error = success ? null : {
  category: 'output_quality',
  type: 'json_parse_failure',
  message: parseErrors.join('; ') || 'Could not parse critic JSON',
  provider: callLLM.provider_used || 'unknown',
  model: callLLM.model_used || 'unknown'
};

// Normalize issues to a flat array; derive counts from per-issue severity.
const rawIssues = Array.isArray(parsed?.issues) ? parsed.issues : [];
const normSeverity = (s) => String(s || '').toLowerCase().trim();
const issues = rawIssues.map((it) => ({
  section: it?.section || '',
  issue: it?.issue || '',
  suggestion: it?.suggestion || '',
  severity: normSeverity(it?.severity)
}));

const criticalCount = issues.filter((i) => i.severity === 'critical').length;
const majorCount = issues.filter((i) => i.severity === 'major').length;
const minorCount = issues.filter((i) => i.severity === 'minor').length;
const total = issues.length;

console.log(`[Agent 5] Total issues: ${total} (critical: ${criticalCount}, major: ${majorCount}, minor: ${minorCount})`);
console.log(`[Agent 5] Tokens: ${callLLM.input_tokens || 0}in + ${callLLM.output_tokens || 0}out + ${callLLM.cached_input_tokens || 0}cached + ${callLLM.cache_write_tokens || 0}cache_write`);

return {
  json: {
    success,
    summary: parsed?.summary || '',
    issues,
    preserve: parsed?.preserve || [],
    total_issues: total,
    critical_count: criticalCount,
    major_count: majorCount,
    minor_count: minorCount,
    tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
    cached_input_tokens: callLLM.cached_input_tokens || 0,
    cache_write_tokens: callLLM.cache_write_tokens || 0,
    model_used: callLLM.model_used || 'unknown',
    provider_used: callLLM.provider_used || 'unknown',
    errors: parseErrors,
    error
  }
};

// Set Inputs â€” Agent 5: Critic
// Critic plays the recruiter/HR role: sees ONLY the resume + JD. No master_doc.
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') {
    cleaned = cleaned.substring(1);
  }
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt);
const descriptionHtml = strip(trigger.description_html);
const resumeMarkdown = strip(trigger.resume_markdown);

// verifier may arrive as Object or JSON-string
let verifier = trigger.verifier;
if (typeof verifier === 'string') {
  let raw = verifier;
  while (raw.length > 0 && raw.charAt(0) === '=') raw = raw.substring(1);
  try {
    verifier = JSON.parse(raw);
  } catch (e) {
    console.log('[Agent 5 Set Inputs] verifier not parseable JSON, defaulting to empty');
    verifier = {};
  }
}
verifier = verifier || {};
if (verifier.result && typeof verifier.result === 'object') {
  verifier = verifier.result;
}

const provider = strip(config.provider_critic);
if (!provider) {
  throw new Error('[Agent 5] config.provider_critic is required. Set it in your config sheet (anthropic | openai | gemini).');
}

const model = strip(config.model_critic);
if (!model) {
  throw new Error('[Agent 5] config.model_critic is required. Set it in your config sheet.');
}

const maxTokens = Number(config.max_tokens_critic);
if (!maxTokens || Number.isNaN(maxTokens)) {
  throw new Error('[Agent 5] config.max_tokens_critic is required and must be a number.');
}

console.log(`[Agent 5 Set Inputs] resume_markdown: ${resumeMarkdown.length} chars, verifier: verdict=${verifier.verdict || 'unknown'}, ${(verifier.issues || []).length} issues, provider: ${provider}, model: ${model}`);

return {
  json: {
    config,
    system_prompt: systemPrompt,
    description_html: descriptionHtml,
    resume_markdown: resumeMarkdown,
    verifier,
    provider,
    model,
    max_tokens: maxTokens
  }
};

// Build Prompt â€” Agent 5: Critic
// Persona (recruiter/HR screener), issue categories, and severity calibration
// live in system_prompt (prompts sheet). The Critic sees ONLY the resume + JD â€”
// it does NOT receive the master career document. Its job is to assess fit the
// way a recruiter would: judge the resume as written against the JD, flag gaps
// and weaknesses. It names WHAT is missing/weak relative to the JD; it does NOT
// prescribe which specific facts to add (that's the refiner's job, grounded in
// the master). This node injects the OUTPUT CONTRACT (JSON shape the Refiner
// consumes) and per-job inputs.
// Mode: Run Once for Each Item

const input = $input.item.json;
const descriptionHtml = input.description_html || '';
const resumeMarkdown = input.resume_markdown || '';
const systemPromptFromDoc = input.system_prompt || '';

// Validation
if (!systemPromptFromDoc || systemPromptFromDoc.length < 100) {
  throw new Error(`[Agent 5] system_prompt missing or too short (${systemPromptFromDoc.length} chars). Check Prompt Loader output and orchestrator mapping.`);
}
if (!resumeMarkdown || resumeMarkdown.length < 30) {
  throw new Error(`[Agent 5] resume_markdown missing or too short (${resumeMarkdown.length} chars)`);
}
if (!descriptionHtml || descriptionHtml.length < 30) {
  throw new Error(`[Agent 5] description_html missing or too short (${descriptionHtml.length} chars)`);
}

console.log(`[Build Prompt] resume: ${resumeMarkdown.length} chars, JD: ${descriptionHtml.length} chars`);
console.log(`[Build Prompt] systemPromptFromDoc: ${systemPromptFromDoc.length} chars`);

// Pipeline-level output contract â€” JSON shape the Refiner (Agent 6) depends on.
OUTPUT_CONTRACT = `# OUTPUT CONTRACT (set by pipeline, do not override)

Output EXACTLY this JSON. No preamble, no markdown fences, no commentary outside JSON:

{
  "summary": "<1-2 sentence top-level assessment>",
  "issues": [
    {
      "section": "<section identifier>",
      "issue": "<one-sentence description of the problem, judged against the JD>",
      "suggestion": "<concrete direction for improvement: what the resume should strengthen or surface to better match the JD. Describe WHAT is needed, not invented specifics â€” do not fabricate facts, metrics, or experience the resume does not show>",
      "severity": "critical" or "major" or "minor"
    }
  ],
  "preserve": ["<strength 1>", "<strength 2>"]
}

Every issue object must have section, issue, suggestion, and severity. The severity field is REQUIRED on every issue and must be exactly one of: "critical", "major", "minor".
- critical: actively undermines the application â€” buries a key qualification the resume does show, off-target summary, or a missing must-have the JD requires.
- major: a clear missed opportunity â€” unquantified impact, weak verbs on important bullets, suboptimal ordering, or a JD priority the resume underplays.
- minor: polish â€” phrasing, parallelism, tightening.

You are assessing the resume as a recruiter would: you see only the resume and the JD. Judge fit, positioning, and clarity against the JD. Flag where the resume fails to make the case the JD asks for. Do NOT invent or prescribe specific facts, metrics, or experience â€” describe what is missing or weak; surfacing real content to fix it is handled downstream.

The issues array may be empty if there are no issues. List issues in severity order: all critical first, then major, then minor. The preserve array must contain 2-4 strengths that should not be touched.`;

const system = systemPromptFromDoc + '\n\n' + OUTPUT_CONTRACT;

const userMessage = `Critique the resume below against the target JD, as a recruiter screening for fit.

# FULL JOB DESCRIPTION
${descriptionHtml}

# CANDIDATE'S TAILORED RESUME
${resumeMarkdown}`;

console.log(`[Build Prompt] Final system: ${system.length} chars, user: ${userMessage.length} chars`);

return {
  json: {
    ...input,
    system,
    user_message: userMessage,
    prompt_chars: system.length + userMessage.length
  }
};

// Build Cascade Output â€” Agent 5
// Mode: Run Once for All Items
// Fires when upstream agent failed. Passes upstream error through unchanged.
// Flat output shape matches Agent 5 Format Output for downstream consumer (Agent 6) compatibility.

const trigger = $('Trigger').first().json;
const upstreamError = trigger.cascade_error || {};

console.log(`[Agent 5] CASCADE â€” skipping due to ${upstreamError.source_agent || 'upstream'}: ${upstreamError.category || 'unknown'}`);

return {
  json: {
    success: false,
    cascaded: true,
    overall_assessment: '',
    critical_issues: [],
    major_issues: [],
    minor_issues: [],
    preserve: [],
    total_issues: 0,
    critical_count: 0,
    major_count: 0,
    minor_count: 0,
    tokens: { input: 0, output: 0 },
    cached_input_tokens: 0,
    cache_write_tokens: 0,
    model_used: 'skipped',
    provider_used: 'skipped',
    errors: [`cascade: ${upstreamError.source_agent || 'upstream'}:${upstreamError.category || 'unknown'}`],
    error: upstreamError
  }
};
